ALGORITHM EventDrivenImageProcessing
INPUT: Image file uploaded to S3 bucket
OUTPUT: Thumbnail saved to destination bucket

BEGIN
  // Step 1: Event Source (User uploads image)
  EVENT FileUploadEvent(file_name, bucket_name, timestamp)

  // Step 2: Event Router (S3 triggers Lambda on ObjectCreated)
  TRIGGER LambdaFunction(ImageProcessor) ON Event = "s3:ObjectCreated"

  // Step 3: Serverless Function Execution
  FUNCTION ImageProcessor(event_data)
  BEGIN
    // Extract bucket and object key from event
    source_bucket <- event_data.bucket.name
    object_key <- event_data.object.key

    // Step 4: Read the image from source bucket
    image_data <- READ_FROM_S3(source_bucket, object_key)

    // Step 5: Process the image (create thumbnail)
    thumbnail <- RESIZE(image_data, width=200, height=200)

    // Step 6: Define destination key
    destination_key <- "thumbnails/" + object_key

    // Step 7: Save thumbnail to destination bucket
    WRITE_TO_S3("processed-images-bucket", destination_key, thumbnail)

    // Step 8: Return success status
    RETURN {"status": "success", "thumbnail": destination_key}
  END FUNCTION

  // Step 9: Optional - Send notification
  PUBLISH_TO_SNS("Image processing complete: " + object_key)
END

import boto3
from botocore.exceptions import ClientError
import logging
import time

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class CloudFormationManager:
    """Manager for AWS CloudFormation Infrastructure as Code operations"""

    def __init__(self, region_name='us-east-1'):
        """Initialize CloudFormation client"""
        self.cf_client = boto3.client('cloudformation', region_name=region_name)
        self.stack_name = 'ImageProcessingStack'

    def get_template(self):
        """Define CloudFormation template as dictionary (Infrastructure as Code)"""
        # This JSON template defines the entire event-driven architecture
        template = {
            "AWSTemplateFormatVersion": "2010-09-09",
            "Description": "Event-driven image processing with S3 and Lambda",
            "Parameters": {
                "EnvironmentName": {
                    "Type": "String",
                    "Default": "production",
                    "Description": "Environment name for resource naming"
                },
                "ThumbnailSize": {
                    "Type": "Number",
                    "Default": 200,
                    "Description": "Thumbnail width in pixels"
                }
            },
            "Resources": {
                # Source S3 Bucket - where users upload images
                "SourceBucket": {
                    "Type": "AWS::S3::Bucket",
                    "Properties": {
                        "BucketName": {
                            "Fn::Sub": "image-source-${EnvironmentName}"
                        },
                        "VersioningConfiguration": {
                            "Status": "Enabled"
                        }
                    }
                },
                # Destination S3 Bucket - for processed thumbnails
                "ThumbnailBucket": {
                    "Type": "AWS::S3::Bucket",
                    "Properties": {
                        "BucketName": {
                            "Fn::Sub": "image-thumbnails-${EnvironmentName}"
                        }
                    }
                },
                # IAM Role for Lambda execution
                "LambdaExecutionRole": {
                    "Type": "AWS::IAM::Role",
                    "Properties": {
                        "RoleName": {
                            "Fn::Sub": "image-processor-role-${EnvironmentName}"
                        },
                        "AssumeRolePolicyDocument": {
                            "Version": "2012-10-17",
                            "Statement": [{
                                "Effect": "Allow",
                                "Principal": {
                                    "Service": "lambda.amazonaws.com"
                                },
                                "Action": "sts:AssumeRole"
                            }]
                        },
                        "ManagedPolicyArns": [
                            "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
                        ]
                    }
                },
                # Lambda Function - the serverless compute
                "ImageProcessorFunction": {
                    "Type": "AWS::Lambda::Function",
                    "Properties": {
                        "FunctionName": {
                            "Fn::Sub": "image-processor-${EnvironmentName}"
                        },
                        "Handler": "index.handler",
                        "Runtime": "python3.9",
                        "Role": {
                            "Fn::GetAtt": "LambdaExecutionRole.Arn"
                        },
                        "MemorySize": 512,
                        "Timeout": 30,
                        "Environment": {
                            "Variables": {
                                "THUMBNAIL_SIZE": {"Ref": "ThumbnailSize"},
                                "DEST_BUCKET": {"Ref": "ThumbnailBucket"}
                            }
                        },
                        "Code": {
                            "ZipFile": """import boto3\nimport io\n\ndef handler(event, context):\n    s3 = boto3.client('s3')\n    bucket = event['Records'][0]['s3']['bucket']['name']\n    key = event['Records'][0]['s3']['object']['key']\n    file_byte = s3.get_object(Bucket=bucket, Key=key)['Body'].read()\n    # Process image and save thumbnail\n    return {'statusCode': 200}"""
                        }
                    }
                }
            },
            "Outputs": {
                "SourceBucketName": {
                    "Description": "Name of the source S3 bucket",
                    "Value": {"Ref": "SourceBucket"}
                },
                "LambdaFunctionArn": {
                    "Description": "ARN of the image processing Lambda function",
                    "Value": {"Fn::GetAtt": "ImageProcessorFunction.Arn"}
                }
            }
        }
        return template

    def create_stack(self, parameters=None):
        """Create CloudFormation stack from the template"""
        try:
            template = self.get_template()

            stack_params = []
            if parameters:
                for key, value in parameters.items():
                    stack_params.append({'ParameterKey': key, 'ParameterValue': value})

            response = self.cf_client.create_stack(
                StackName=self.stack_name,
                TemplateBody=str(template),  # In practice, use json.dumps(template)
                Parameters=stack_params,
                Capabilities=['CAPABILITY_IAM'],
                EnableTerminationProtection=False
            )

            stack_id = response['StackId']
            logger.info(f"Stack creation initiated: {stack_id}")

            # Wait for stack creation to complete
            self._wait_for_stack_complete(stack_id)

            return stack_id
        except ClientError as e:
            logger.error(f"Error creating stack: {e}")
            return None

    def _wait_for_stack_complete(self, stack_id, timeout=300):
        """Wait for stack creation/update to complete"""
        elapsed = 0
        while elapsed < timeout:
            response = self.cf_client.describe_stacks(StackId=stack_id)
            stack = response['Stacks'][0]
            status = stack['StackStatus']

            if status == 'CREATE_COMPLETE':
                logger.info("Stack created successfully!")
                return True
            elif status == 'CREATE_FAILED':
                logger.error(f"Stack creation failed: {stack.get('StackStatusReason', 'Unknown')}")
                return False
            elif 'ROLLBACK' in status:
                logger.error("Stack creation rolled back")
                return False

            logger.info(f"Waiting... Current status: {status}")
            time.sleep(10)
            elapsed += 10

        logger.warning("Timeout waiting for stack creation")
        return False

    def describe_stack(self):
        """Get stack details and outputs"""
        try:
            response = self.cf_client.describe_stacks(StackName=self.stack_name)
            stack = response['Stacks'][0]

            logger.info(f"Stack: {stack['StackName']}")
            logger.info(f"Status: {stack['StackStatus']}")

            if 'Outputs' in stack:
                logger.info("Outputs:")
                for output in stack['Outputs']:
                    logger.info(f"  {output['OutputKey']}: {output['OutputValue']}")

            return stack
        except ClientError as e:
            logger.error(f"Error describing stack: {e}")
            return None

    def delete_stack(self):
        """Delete the CloudFormation stack and all resources"""
        try:
            self.cf_client.delete_stack(StackName=self.stack_name)
            logger.info("Stack deletion initiated")
            return True
        except ClientError as e:
            logger.error(f"Error deleting stack: {e}")
            return False

